INSERT INTO ITPAPP.TAAABB_BRDOCM (DOC_MNG_NO,REQ_NM,REQ_DTT,BZ_DTT,FSG_TLM,DEL_YN,FST_ENR_DTM,FST_ENR_USID,GUID,GUID_PRG_SNO,LST_CHG_DTM,LST_CHG_USID,DOC_VRS,REQ_INF) VALUES
	 ('DOC-2026-0000','PAMS 급여 관련 자녀수당 신규 추가','기존 시스템 기능 추가','PAMS(인사정보시스템)',TIMESTAMP'2026-03-20 00:00:00','N',TIMESTAMP'2026-03-14 20:03:06','K140024','508d71fb-a75b-4b4f-8c98-975950ddc9e1',1,TIMESTAMP'2026-04-06 22:04:18','K140024',1,TO_CLOB('<h3 id="heading-zpwiko2sq" style="scroll-margin-top: 100px;">PAMS 급여 관련 자녀수당 신규 추가</h3><h4 id="heading-hzfe6xiji" style="scroll-margin-top: 100px;">목표/목적</h4><p>직원 복지 증진 및 공정한 급여 지급을 위해 PAMS 시스템에 자녀수당 지급 기능을 추가하여, 직원의 자녀 유무 및 수에 따른 수당을 정확하게 산정하고 지급하는 것을 목표로 합니다.</p><h4 id="heading-q4yxssa1v" style="scroll-margin-top: 100px;">주요 내용</h4><p>PAMS 시스템 내 급여 계산 로직에 직원의 자녀 유무 및 자녀 수에 따른 ''자녀수당''을 신규로 추가하여 지급할 수 있도록 기능을 구현합니다.</p><ul><li><p><strong>자녀수당 지급 기준:</strong> (사용자 요청에 따라 표 형식으로 변경 및 달러 기준 추가)</p><div class="tableWrapper"><table style="table-layout: fixed; margin-left: 0px; margin-right: auto;"><tbody><tr><th colspan="1" rowspan="1" colwidth="128" style="width: 128px;"><p>자녀 수</p></th><th colspan="1" rowspan="1" colwidth="128" style="width: 128px;"><p>지급 금액 (월, KRW)</p></th><th colspan="1" rowspan="1" colwidth="128" style="width: 128px;"><p>지급 금액 (월, USD)</p></th></tr><tr><td colspan="1" rowspan="1" colwidth="128" style="width: 128px;"><p>첫째 자녀</p></td><td colspan="1" rowspan="1" colwidth="128" style="width: 128px;"><p>10만원</p></td><td colspan="1" rowspan="1" colwidth="128" style="width: 128px;"><p>30$</p></td></tr><tr><td colspan="1" rowspan="1" colwidth="128" style="width: 128px;"><p>둘째 자녀</p></td><td colspan="1" rowspan="1" colwidth="128" style="width: 128px;"><p>20만원</p></td><td colspan="1" rowspan="1" colwidth="128" style="width: 128px;"><p>50$</p></td></tr><tr><td colspan="1" rowspan="1" colwidth="128" style="width: 128px;"><p>셋째 이상 자녀</p></td><td colspan="1" rowspan="1" colwidth="128" style="width: 128px;"><p>30만원</p></td><td colspan="1" rowspan="1" colwidth="128" style="width: 128px;"><p>100$</p></td></tr></tbody></table></div></li><li><p><strong>지급 대상:</strong> 만 20세 미만의 자녀(또는 대학생의 경우 만 24세 미만)를 둔 재직 중인 직원으로 정의합니다. (참고: 공무원 규정은 ''19세 미만'' 또는 ''19세 이상 장애인''을 기준으로 합니다. 이 시스템은 귀사의 자체 규정을 따릅니다.)</p></li><li><p><strong>지급 조건:</strong> 자녀가 주민등록표상 직원의 직계비속으로 등재되어야 하며, 회사의 별도 자녀수당 지급 규정에 따릅니다. (공무원 규정의 ''부양가족'' 정의를 참고하여, 실제 생계를 같이 하는지 여부 또는 별거 예외 조항 등 추가 검토가 필요할 수 있습니다.)</')||TO_CLOB('p></li><li><p><strong>세부 내용:</strong> 자녀 연령 기준은 매월 급여 계산 시점 기준으로 판단하며, 자녀 수당은 비과세 처리됩니다.</p></li></ul><h4 id="heading-wwtc1fw66" style="scroll-margin-top: 100px;">화면 구성 : (변경) 기존 인사정보 등록 화면 및 급여 기준 설정 화면</h4><p>기존 인사정보 등록 화면(직원 상세 정보)에 자녀수당 적용을 위한 정보 입력 및 확인 필드를 추가하고, 급여 계산 기준 설정 화면에 자녀수당의 지급 기준을 설정할 수 있는 섹션을 추가합니다.</p><ul><li><p><strong>인사정보 등록 화면 (변경):</strong></p><ul><li><p>직원별 자녀 정보(이름, 생년월일, 관계) 입력/수정 필드.</p></li><li><p>각 자녀별 자녀수당 적용 여부 체크박스 (예: 중단 사유 발생 시 체크 해제).</p></li><li><p>자녀수당 적용 시작일/종료일 필드.</p></li><li><p>자녀의 장애 여부 및 등급 입력 필드 (필요시, 19세 이상 자녀 지급 조건에 활용).</p></li></ul></li><li><p><strong>급여 계산 기준 설정 화면 (변경):</strong></p><ul><li><p>자녀수당 지급 기준 금액 설정 (예: 첫째, 둘째, 셋째 이상에 대한 KRW 및 USD 금액).</p></li><li><p>자녀수당 지급 대상 연령 기준 설정 (예: 만 20세 미만, 대학생 만 24세 미만).</p></li><li><p>자녀수당 지급 조건 설정 (예: 재직 여부, 자녀 등록 여부 등).</p></li><li><p>(추가 제안) 통화 선택 및 환율 적용 기준 설정 (예: KRW/USD 선택, 기준 환율 적용 방식 등).</p></li><li><p>19세 이상 자녀에게 자녀수당을 지급할 경우, 장애인 등록 기준 또는 대학생 등록 기준을 설정할 수 있는 필드.</p></li></ul></li><li><p><strong>(선택 사항) 자녀수당 지급 내역 조회 화면 (신규):</strong></p><ul><li><p>직원별 또는 전체 직원의 자녀수당 지급 내역을 조회하고 엑셀로 다운로드할 수 있는 화면.</p></li></ul></li></ul><p><strong>화면 구성 다이어그램 (예시)</strong><br>(여기에 화면 흐름 또는 UI 스케치를 다이어그램으로 도식화하여 표현해주세요. 예: UI Wireframe, Screen Flow Diagram)</p><h4 id="heading-key0tbbny" style="scroll-margin-top: 100px;">업무 절차</h4><p>자녀수당 신규 추가와 관련된 전/후 업무 절차를 정의합니다.</p><ol><li><p><strong>[인사팀] 자녀 정보 등록 및 관리:</strong> 인사 담당자는 PAMS 시스템의 인사정보 등록 화면에서 직원의 자녀 정보를 최초 등록하거나 변경(출생, 성년 도달 등)합니다.</p></li><li><p><strong>[시스템] 자녀수당 지급 대상 판단:</strong> 시스템은 등록된 자녀 정보(생년월일, 자녀수 등)와 급여 기준 설정 화면에 정의된 지급 기준을 바탕으로 매월 급여 계산 시 자녀수당 지급 대상 여부 및 지급 금액을 판단합니다.</p></li><li><p><strong>[시스템] 급여 계산 및 반영:</strong> 급여 계산 시 자녀수당을 산정하여 총 급여액에 포함합니다.</p></li><li><p><strong>[인사팀/경영지원팀] 지급 내역 확인:</strong> (선택 사항) 자녀수당 지급 내역 조회 화면을 통해 지급 현황을 확인하고 정기적으로 보고서를 생성합니다.</p></li></ol><p><strong>업무 절차 다이어그램 (예시)</strong><br>(여기에 업무 흐름을 다이어그램으로 도식화하여 표현해주세요. 예: Activity Diagram, Flowchart)</p><h4 id="heading-jm5mdo8kt" style="scroll')||TO_CLOB('-margin-top: 100px;">참조 업무 : 기존 PAMS 내 ''가족수당'' 또는 ''직책수당'' 계산 로직</h4><p>PAMS 시스템 내에서 이미 구현되어 있는 ''가족수당'' 또는 ''직책수당'' 등의 다른 수당 계산 로직을 참조하여 개발 효율성을 높일 수 있습니다. 특히, 직원 정보와 연동하여 수당을 지급하는 방식 및 급여 명세서에 반영되는 방식 등을 참고할 수 있습니다.</p><h4 id="heading-ouku2nnvm" style="scroll-margin-top: 100px;">구현 시 고려사항(예외 처리 등)</h4><ol><li><p><strong>자녀 연령 변화에 따른 자동 지급 중단:</strong> 자녀가 지급 대상 연령(예: 만 20세)에 도달했을 경우, 해당 월부터 자녀수당이 자동으로 지급 중단되도록 처리 로직을 구현해야 합니다.</p></li><li><p><strong>휴직/퇴직 등 고용 상태 변화 처리:</strong> 출산휴가, 육아휴직, 퇴직 등 직원의 고용 상태 변화에 따른 자녀수당 지급 여부 및 중단/재개 로직을 명확히 정의하고 반영해야 합니다. (예: 육아휴직 중에는 지급 중단, 복직 시 재개)</p></li><li><p><strong>징계 및 기타 고용 상태 변화에 따른 지급 처리:</strong> 강등, 정직, 감봉, 직위해제 등 징계 처분 및 기타 특수 고용 상태(예: 파견, 휴직 유형별)에 따른 자녀수당 지급 여부 및 감액/중단 로직을 명확히 정의하고 반영해야 합니다. (공무원 규정 제8항 참조)</p></li><li><p><strong>지급 기준의 유연한 변경 가능성:</strong> 향후 자녀수당 지급 기준(금액, 대상 연령, 조건 등)이 변경될 경우, 시스템 설정만으로 유연하게 대응할 수 있도록 구현해야 합니다.</p></li><li><p><strong>소급 적용 및 정산 처리:</strong> 특정 사유(예: 자녀 정보 지연 등록)로 인해 자녀수당을 소급하여 적용해야 하는 경우, 이를 처리할 수 있는 기능 및 정산 로직을 고려해야 합니다.</p></li><li><p><strong>중복 수당 지급 방지:</strong> 직원 본인 또는 배우자가 공무원이거나 다른 공공기관 등에서 유사한 성격의 수당을 지급받는 경우, 자녀수당이 중복 지급되지 않도록 방지 로직을 구현해야 합니다. (공무원 규정 제4항, 제5항 참조)</p></li><li><p><strong>세금 처리 기준:</strong> 자녀수당의 과세/비과세 여부를 명확히 확인하고 급여 계산 시 정확하게 반영해야 합니다.</p></li><li><p><strong>데이터 이력 관리:</strong> 자녀수당 지급 기준 변경, 자녀 정보 변경 등 주요 데이터 변경 이력을 관리하여 추후 감사 및 검토에 활용할 수 있도록 합니다.</p></li><li><p><strong>환율 적용 및 통화 선택:</strong> USD 지급 시, 기준 환율(예: 월초 고시 환율, 특정일자 환율 등)을 어떻게 적용할지 명확히 정의해야 합니다. 또한, 직원에 따라 지급 통화(KRW 또는 USD)를 선택할 수 있는 기능이 필요한지 여부를 확인해야 합니다.</p></li><li><p><strong>부정 수급 방지 및 처리:</strong> 허위 정보 등록 등으로 자녀수당이 부정하게 지급된 경우, 해당 금액을 환수하고 일정 기간 수당 지급을 정지하는 등의 처리 방안을 고려해야 합니다. (공무원 규정 제10항 참조)</p></li><li><p><strong>자녀 정보 확인 절차:</strong> 자녀수당 지급을 위한 자녀 정보(관계, 연령 등)의 정확성을 확인하기 위한 절차(예: 주민등록표 열람, 등본/초본 제출 등)를 정의하고 시스템에 반영해야 합니다. (공무원 규정 제9항 참조)</p></li></ol><h4 id="heading-miu4i4xo4" style="scroll-margin-top: 100px;">단위 테스트 케이스</h4><ol><li><p>자녀가 없는 직원의 급여 계산 시 자녀수당이 정확히 0으로 계산되는지 확인.</p></li><')||TO_CLOB('li><p>자녀가 1명(만 10세)인 직원의 급여 계산 시 첫째 자녀수당(예: 10만원 또는 30$)이 정확히 계산되는지 확인.</p></li><li><p>자녀가 3명(만 5세, 만 15세, 만 18세)인 직원의 급여 계산 시 첫째, 둘째, 셋째 자녀수당이 합산되어 정확히 계산되는지 확인.</p></li><li><p>자녀 중 한 명이</p></li></ol><p></p>')),
	 ('DOC-2026-0001','Excalidraw Test','Bug Fix Verification',NULL,NULL,'N',TIMESTAMP'2026-03-14 20:45:34','K140024','77083d4f-0f11-4420-9325-a7594e6e5517',1,TIMESTAMP'2026-04-11 17:11:42','K140024',1,TO_CLOB('<div class="tableWrapper"><table style="table-layout: fixed; margin-left: 0px; margin-right: auto;"><tbody><tr><th colspan="2" rowspan="1" colwidth="150,150" style="text-align: center; width: 300px;"><p style="text-align: center;">비고</p></th><th colspan="1" rowspan="1" colwidth="150" style="width: 150px;"><p></p></th></tr><tr><td colspan="1" rowspan="3" colwidth="150" style="text-align: center; width: 150px;"><p style="text-align: center;">자본예산</p></td><td colspan="1" rowspan="1" colwidth="150" style="text-align: center; width: 150px;"><p style="text-align: center;">개발비</p></td><td colspan="1" rowspan="1" colwidth="150" style="width: 150px;"><p>CD</p></td></tr><tr><td colspan="1" rowspan="1" colwidth="150" style="text-align: center; width: 150px;"><p style="text-align: center;">기계장치</p></td><td colspan="1" rowspan="1" colwidth="150" style="width: 150px;"><p></p></td></tr><tr><td colspan="1" rowspan="1" colwidth="150" style="text-align: center; width: 150px;"><p style="text-align: center;">기타무형자산</p></td><td colspan="1" rowspan="1" colwidth="150" style="width: 150px;"><p></p></td></tr></tbody></table></div><p></p>')),
